mapper.select:
select ei.*
from scheduler_event_instance ei



            and (ei.event_name like concat('%', #{query.eventKeyword}, '%')
                or ei.id::text = #{query.eventKeyword}
                or ei.event_id::text = #{query.eventKeyword})


            and ei.event_type = #{query.eventType}


            and ei.flow_instance_id = #{query.flowInstanceId}


            and ei.task_instance_id = #{query.taskInstanceId}


            and ei.effect_time >= #{query.effectStartTime}


            and ei.effect_time <= #{query.effectEndTime}



order by ei.effect_time desc nulls last

select *
from scheduler_event_instance
where event_id = #{eventId}::uuid
  and event_type = #{type}
  and effect_time <= #{eventTime}
  and effect_end_time >= #{eventTime}
order by effect_time desc

select * from scheduler_event_instance where event_id = #{eventId}::uuid
and effect_time = #{eventTime}
order by effect_time desc limit 1
